package ui.librarian;
import database.LibraryRepository;import model.DisplayIds;import database.LibraryRepository.FineRow;import javafx.beans.property.*;import javafx.collections.*;import javafx.fxml.FXML;import javafx.scene.control.*;import java.sql.SQLException;
public class FinesController extends NavigationController{@FXML private TableView<FineRow> table;@FXML private TableColumn<FineRow,String> idCol,checkoutCol,memberCol,amountCol,statusCol;@FXML private Label count;private final LibraryRepository repo=new LibraryRepository();@FXML private void initialize(){idCol.setCellValueFactory(v->new ReadOnlyStringWrapper(DisplayIds.shortId("f",v.getValue().id())));checkoutCol.setCellValueFactory(v->new ReadOnlyStringWrapper(DisplayIds.shortId("co",v.getValue().checkoutId())));memberCol.setCellValueFactory(v->new ReadOnlyStringWrapper(v.getValue().member()));amountCol.setCellValueFactory(v->new ReadOnlyStringWrapper(String.format("$%.2f",v.getValue().amount())));statusCol.setCellValueFactory(v->new ReadOnlyStringWrapper(v.getValue().status()));refresh();}@FXML private void refresh(){try{var rows=repo.findFines("");table.setItems(FXCollections.observableArrayList(rows));count.setText(rows.isEmpty()?"No fines have been recorded yet.":rows.size()+" fine records");}catch(SQLException e){showError("Fines could not be loaded",e);}}@FXML private void paid(){resolve("paid");}@FXML private void waive(){resolve("waived");}private void resolve(String status){var row=table.getSelectionModel().getSelectedItem();if(row==null){new Alert(Alert.AlertType.INFORMATION,"Select a fine first.").showAndWait();return;}try{repo.resolveFine(row.id(),status);refresh();}catch(SQLException e){showError("The fine could not be updated",e);}}}
